var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"으아, 피곤하다. 오늘도 고생하셨어요, 경정님.","JPN":"はあ、疲れた。お疲れ様です、警視様。","ENG":"Phew, I'm pooped. Another day of hard work, Major.","TWN":"哇～累死了。今天也辛苦了，警正大人。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여기 떡볶이 2인분이요!","JPN":"餃子2人前、お願いします！","ENG":"Could we get two servings of spicy rice cake here?","TWN":"這邊要兩份辣炒年糕！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"예~ 바로 준비해드릴게요.","JPN":"はい～かしこまりました。","ENG":"Sure, coming right up.","TWN":"是～馬上來。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐 마시고 싶은 거 있으세요?","JPN":"何か飲みますか？","ENG":"Would you like anything to drink?","TWN":"妳想喝點什麼嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어...... 응...... 아니, 괜찮아.","JPN":"あ……えっと……いや、大丈夫。","ENG":"Uh... Sure... Actually, no thanks.","TWN":"啊……嗯……不用，沒有關係。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 한참 뛰어다니셔서 목마르실 텐데.","JPN":"はは。ずっと走り回ったのに、のど渇かないんですか？","ENG":"Hah hah, you must be parched from all the running around though.","TWN":"哈哈，妳跑了這麼久，一定口渴了吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저기, 강소영 경위.","JPN":"その、マエカワ警部補。","ENG":"Hey, Lieutenant Kang?","TWN":"那個，姜警衛。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네?","JPN":"はい、何でしょうか？","ENG":"Yes?","TWN":"什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......왜 화내지 않는 거야? 내가 상사라서?","JPN":"……なぜ怒らないの？　私が上司だから？","ENG":"Why aren't you getting mad at me? Is it because I outrank you?","TWN":"……為什麼妳都不生氣？是因為我是上司嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 무슨 말이세요?","JPN":"急にどうしたんですか？","ENG":"What are you talking about ma'am?","TWN":"妳在說什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"왜 모르는 척 해!","JPN":"とぼけないで！","ENG":"Don't pretend you don't know what I'm talking about!","TWN":"不要裝傻了！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아까도 내가 성급하게 나서는 바람에 작전이 틀어질 뻔 했잖아!","JPN":"さっきも私が出しゃばったせいで、作戦が台無しになるところだったんでしょ！","ENG":"I almost compromised the mission again because I rushed out recklessly!","TWN":"剛才也是，因為我太心急，害作戰差點就泡湯了！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"앗, 그거 아직도 마음에 담아두고 계셨어요?","JPN":"あ、まだそれを気にしてたんですか？","ENG":"Oh, you're still upset over that?","TWN":"喔，妳還把那件事放在心上啊？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지난 일은 그냥 잊어버리라니까요.","JPN":"もう終わったことだから、忘れてください。","ENG":"Like I said, let bygones be bygones.","TWN":"過去的事情就忘掉它吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"결국 도망친 녀석들도 다 잡긴 했잖아요?","JPN":"逃げたやつらも、全員逮捕したじゃないですか。","ENG":"We managed to round up all the bad guys in the end, didn't we?","TWN":"我們最後不是也把逃跑的傢伙抓住了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 과정에서 차가 좀 망가지긴 했지만...... 하하.","JPN":"まあ、車は少し壊れちゃいましたけど……はは。","ENG":"Although I guess the car took a little damage in the process... Hah hah...","TWN":"雖然追逐的過程中車有點壞掉了……哈哈。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위...... 늘 그렇게 웃어넘기려 하지만 말고 솔직하게 말해줬으면 좋겠어.","JPN":"マエカワ警部補……笑ってごまかさずに、正直に言いなさい。","ENG":"Lieutenant Kang... I wish you'd be straight with me for once, instead of just laughing it off.","TWN":"姜素英警衛……不要老是用笑容蒙混過去，希望妳老實地說出來。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"나도 내가 잘못했다는 것쯤은 알고 있으니까.","JPN":"私にだって、自分が悪かったという自覚はあるんだから。","ENG":"I know I made a mistake this time.","TWN":"我好歹知道我有做錯的地方。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 누구나 실수는 할 수 있는 거죠.","JPN":"いやいや。人間誰しも、ミスをするものです。","ENG":"Aw, come on Major. Everyone makes mistakes.","TWN":"哎呀，誰都會有失誤的時候啦。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아니! 실수라는 건, 무능력자들이 하는 변명일 뿐이라고.","JPN":"いいえ！　ミスというのは、無能力者の言い訳に過ぎない！","ENG":"No! Mistakes are just an excuse for incompetence.","TWN":"不對！所謂的失誤，只不過是無能力者的藉口。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 말이 맞을 지도 모르겠네요.","JPN":"そうかもしれませんね。","ENG":"You may be right.","TWN":"這話說不定沒錯呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"실수를 통해 배운다는 건, 자신의 잘못을 그럴싸하게 포장한 변명이죠.","JPN":"ミスから学ぶというのは、自分の失敗をごまかすための言い訳です。","ENG":"The notion of learning through mistakes may sound like just an excuse for one's faults.","TWN":"所謂通過失誤學習，就像是包裝自己過錯的藉口。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 그렇게 변명을 해서라도, 스스로를 돌보며 성장하는 거에요. 사람은.","JPN":"しかし、そうやって言い訳をして自分の心を守りながら、人は成長します。","ENG":"But even through such excuses, it gives us a chance to reflect back on ourselves and grow. That's how people work.","TWN":"但就算是這樣的藉口，還是能夠反省自己，然後獲得成長，人就是這樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 편이, 스스로를 책망하고 괴롭히는 것보다 나으니까요.","JPN":"その方が自分を責めて傷つくよりマシだから。","ENG":"That beats dwelling in self-pity, after all.","TWN":"這比責備自己、折磨自己來得好多了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......근심 한 번 없었을 것 같은 경위가 그런 말을 하니 설득력이 없네.","JPN":"……悩みがなさそうな警部補が言うと、説得力がないわね。","ENG":"It's not very convincing coming from you, since you never seem to worry about anything.","TWN":"……無憂無慮的警衛說出這種話，還真沒有說服力呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 그럴 리가요. 저도 부서 막내시절엔 실수투성이에 걱정도 많았어요.","JPN":"私も新入りだった頃は、ミスを繰り返したし、悩みも多い方でした。","ENG":"Oh, of course not. I made mistakes and worried all the time when I was the most junior officer in our team.","TWN":"唉呀，這怎麼會呢。我的萌新時代也老是犯錯，很讓人擔心呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"막내? 그러고 보니 예전엔 4기동에도 다른 사람이 있었다고 했지?","JPN":"新入り？　そういえば、以前は第4特別機動捜査隊に他のメンバーがいたのよね？","ENG":"The most junior officer? Come to think of it, you said there were other people in SWAT 4 before as well, huh?","TWN":"新人？聽說之前第四機動隊還有其他人？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼요, 기억하고 계시네요.","JPN":"ええ、覚えてたんですね。","ENG":"That's right. You remembered.","TWN":"是啊，妳還記得啊。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 지금은 보다시피 다 뿔뿔이 흩어졌지만요.","JPN":"まあ、今はご覧の通り、バラバラになっちゃいましたけど。","ENG":"But as you can see, we're all scattered about.","TWN":"不過，正如妳所見，現在已經分崩離析了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……왜 그렇게 됐는데?","JPN":"……何があったの？","ENG":"What happened?","TWN":"……為什麼會變成這樣？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"역시 지난 번에 말한 대로 성과부진에 따른 지원종료 때문인가?","JPN":"やはりこの間言っていた、検挙率の低迷に伴う支援の打ち切りが原因だとか？","ENG":"They cut off support because of the lack of results, like you said?","TWN":"難道是像之前說的一樣，因為業績不佳、無人申請造成的嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 뭐 그런 이유도 있긴 하지만 더 중요한 건 따로 있죠.","JPN":"はは、原因はそれだけじゃないんです。","ENG":"Hah hah, that's part of it, but there's a more important reason.","TWN":"哈哈，是有這個原因沒錯啦，但有別的更重要的理由。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"위험한 카운터 범죄를 전담하다 보니 작은 실수에도 목숨이 오갈 만큼 리스크가 컸거든요.","JPN":"この部署は、危険なカウンターの犯罪を担当しているので、小さいミスが命取りになります。","ENG":"Given how dangerous Counter criminals are, even the smallest mistake can be life-threatening.","TWN":"因為只要負責危險的制裁者犯罪，哪怕是小小的失誤也會有性命之憂，風險特別高。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"실패를 겪어본 사람들은 하나 둘씩 떠났어요.","JPN":"失敗を経験した人たちが、一人ずつ去って行きました。","ENG":"So people eventually left, one by one, once they'd experienced the consequences of their failure.","TWN":"經歷過失敗的人一個接著一個，陸續離開了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자기 실수가 또 동료를 잃게 만들까 봐, 그게 두려웠던 거죠.","JPN":"自分のミスで仲間が命を失うことに、耐えられなくなったんです。","ENG":"They were afraid their mistakes may cost their partners' lives again.","TWN":"因爲他們擔心自己的失誤會再次失去隊友，所以很害怕。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……그렇구나.","JPN":"……そうだったんだ。","ENG":"I see.","TWN":"……原來是這樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런데 경위는 왜 4기동에 남아 있었던 거야?","JPN":"では、なぜ警部補はここに残ってるの？","ENG":"But why did you remain in SWAT 4?","TWN":"不過妳為什麼會留在第4機動隊呢？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저야 뭐. 부서에 혼자 남았을 땐 어차피 책임질 남은 동료가 없었으니까요.","JPN":"私が最後の一人だったからです。仲間がいないから、ミスに怯える必要もありませんでした。","ENG":"Well, as for me... I didn't have anyone to worry about since I was the only person left on the team.","TWN":"我嘛，因為整個部門只剩一個人時，就不用擔心有同事受到牽連嘛。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 남들처럼 관두려고 생각한 적도 없어요.","JPN":"ですが、私は初めから辞めるつもりなどありませんでしたけどね。","ENG":"But I never thought about quitting like the others either.","TWN":"不過我從沒想過要像其他人一樣退出。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"위험한 일이라곤 해도, 어차피 누군가는 짊어져야 할 책임이니까요.","JPN":"危険だけど、結局誰かがやらなければならない仕事なので。","ENG":"As dangerous as it may be, someone's got to do this job, one way or the other.","TWN":"就算是份危險的工作，也總得有人站出來負責才行。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"내가 또 실수하진 않을까....... 내 실수로 누가 다치진 않을까......","JPN":"またミスをするかもしれない……私がミスをしたせいで、誰かがケガをするかもしれない……","ENG":"Sure, I could worry about making mistakes... And whether that mistake could end up getting someone hurt...","TWN":"我會不會又失誤了呢……會不會有人又因為我的失誤受傷呢……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런 최악의 상황을 떠올리며 골골댈 바엔, 그냥 훌훌 털어버리는 편이 낫다는 거죠.","JPN":"そういう最悪の事態を想定して落ち込むくらいなら、早く忘れた方がいいってことです。","ENG":"But it's a lot better to just get on with life than letting those worries keep me down.","TWN":"與其去想到這些最壞的情況，害自己悶悶不樂的，不如把它們忘了比較好。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 왜 그렇게 빤히 쳐다보세요?","JPN":"はは、どうしたんですか？","ENG":"Hah hah, why are you staring at me like that?","TWN":"哈哈，妳幹嘛這樣盯著我看？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그냥, 왠지 딴 사람 같아서.","JPN":"……何だか、別人みたいで。","ENG":"It's just... I've never seen this side of you before.","TWN":"……只是覺得妳好像不是本人。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어쨌든 다시는 그런 실수 반복하는 일 없을 거야. 약속할게.","JPN":"とにかく、もう二度と同じミスを繰り返すことはないわ。約束する。","ENG":"In any case, I'm never going to make a mistake like that again. I promise.","TWN":"總之，我不會再犯今天這樣的失誤了，我向妳保證。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래요. 그런 자세가 중요한 거죠.","JPN":"いいですね。その調子です。","ENG":"Sure. That's the spirit.","TWN":"就是這樣。有這個心非常重要。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여기요! 라면도 두 그릇 추가요!","JPN":"あの！　ラーメンも2杯追加で！","ENG":"Excuse me! Could we get two bowls of ramen too?","TWN":"老闆這裡！再加兩碗拉麵！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};